from flask import Flask, request, jsonify
import pickle
import os
import base64
import numpy as np

app = Flask(__name__)

@app.route('/upload_model', methods=['POST'])
def upload_model():
    if 'model_file' not in request.files:
        return jsonify({'error': 'No model file provided'}), 400
    
    model_file = request.files['model_file']
    
    try:
        model_data = pickle.load(model_file)
        return jsonify({'message': 'Model uploaded successfully'}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/infer', methods=['POST'])
def infer():
    if 'model_name' not in request.json or 'input_data' not in request.json:
        return jsonify({'error': 'Invalid request'}), 400
    
    model_name = request.json['model_name']
    
    # Load the saved model
    try:
        with open(f'models/{model_name}', 'rb') as f:
            model_data = pickle.load(f)
            
        input_data = base64.b64decode(request.json['input_data']).numpy()
        
        try:
            prediction = model_data.predict(input_data)
            return jsonify({'prediction': prediction.tolist()}), 200
        except Exception as e:
            return jsonify({'error': str(e)}), 500
    except Exception as e:
        return jsonify({'error': str(e)}), 404

if __name__ == '__main__':
    app.run(debug=True)